const messages = $("Limit").all().map(item => item.json);

// now en Argentina (UTC-3)
const now = new Date();
const nowArgentina = new Date(now.getTime() - 3 * 60 * 60 * 1000);
const fiveMinutesAgo = new Date(nowArgentina.getTime() - 5 * 60 * 1000);

const recentMessages = messages.filter(msg => {
  const msgDate = new Date(msg.created_at);
  return msgDate >= fiveMinutesAgo && msgDate <= nowArgentina;
});

return recentMessages;

